(()=>{'use strict';
const T=v=>String(v??'').trim(),$=s=>document.querySelector(s);
let psOverlay,psBody,allPsOptions=[];
function cleanPs(v){const parts=T(v).split(/\s+/).filter(Boolean);if(!parts.length)return'';if(parts.length===2&&parts[0]===parts[1])return parts[0];const out=[];parts.forEach(p=>{if(!out.includes(p))out.push(p)});return out.join(' ')}
function sortList(a){return[...new Set((a||[]).map(cleanPs).filter(Boolean))].sort((x,y)=>x.localeCompare(y,'th'))}
function selected(){return sortList(window.DOIT_SELECTED_PS_LIST||[])}
function collectFullPs(){const rows=Array.isArray(window.__doitAllRows)?window.__doitAllRows:(Array.isArray(window.__doitRawRows304)?window.__doitRawRows304:[]);const fromRows=rows.map(r=>cleanPs(r.ps)).filter(Boolean);const el=$('#psSelect');const fromOpt=el?[...el.options].map(o=>cleanPs(o.value||o.textContent)).filter(Boolean):[];const next=sortList([...allPsOptions,...fromRows,...fromOpt]);if(next.length>=allPsOptions.length)allPsOptions=next;return allPsOptions}
function cleanSelect(){const el=$('#psSelect');if(!el)return;[...el.options].forEach(o=>{const c=cleanPs(o.textContent||o.value);if(c){o.textContent=c;o.value=c}})}
function hideLegacyPsSelect(){const el=$('#psSelect');if(!el)return;el.style.position='absolute';el.style.left='-9999px';el.style.width='1px';el.style.height='1px';el.style.opacity='0';el.style.pointerEvents='none';el.tabIndex=-1;el.setAttribute('aria-hidden','true')}
function forceCenteredDate(){if($('#forceCenterDate303'))return;const st=document.createElement('style');st.id='forceCenterDate303';st.textContent='.dateOverlay{align-items:center!important;justify-content:center!important;padding:18px!important}.dateSheet{width:min(92vw,720px)!important;max-height:86vh!important;border-radius:18px!important;box-shadow:0 22px 80px rgba(0,0,0,.38)!important}@media(max-width:520px){.dateOverlay{padding:10px!important}.dateSheet{width:96vw!important;max-height:88vh!important}.dateGrid{grid-template-columns:repeat(2,1fr)!important}}';document.head.appendChild(st)}
function injectPsCss(){if($('#psTickCss303'))return;const st=document.createElement('style');st.id='psTickCss303';st.textContent='.psTickBtn289{width:100%;height:42px;border:1px solid #087b34;background:#f0fdf4;color:#065f46;border-radius:9px;font-weight:950;text-align:left;padding:0 12px;margin-bottom:6px}.psOverlay289{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:171;display:none;align-items:center;justify-content:center;padding:18px}.psOverlay289.on{display:flex}.psSheet289{width:min(92vw,720px);max-height:86vh;background:#fff;border-radius:18px;box-shadow:0 22px 80px #0006;display:flex;flex-direction:column;overflow:hidden}.psHead289{background:#087b34;color:#fff;padding:14px 16px;display:flex;justify-content:space-between;align-items:center;gap:8px;font-size:17px}.psClose289{height:34px;border:1px solid #ffffff66;background:#0001;color:#fff;border-radius:8px;font-weight:900;padding:0 12px}.psSearch289{padding:12px;border-bottom:1px solid #e5e7eb}.psSearch289 input{width:100%;height:44px;border:1px solid #cbd5e1;border-radius:10px;padding:0 12px;font-weight:900;font-size:15px}.psCount289{padding:8px 12px;border-bottom:1px solid #e5e7eb;background:#f8fafc;font-size:13px;font-weight:900;color:#374151}.psBody289{padding:12px;overflow:auto}.psGrid289{display:grid;grid-template-columns:repeat(2,1fr);gap:9px}.psItem289{border:1px solid #d1d5db;background:#fff;border-radius:10px;padding:12px 10px;font-weight:950;text-align:left;font-size:15px;display:flex;gap:8px;align-items:center}.psItem289 i{width:20px;height:20px;border:1px solid #9ca3af;border-radius:5px;display:inline-grid;place-items:center;font-style:normal;flex:0 0 auto}.psItem289.on{border-color:#087b34;background:#ecfdf5;color:#065f27}.psItem289.on i{background:#087b34;color:#fff;border-color:#087b34}.psFoot289{padding:12px;border-top:1px solid #e5e7eb;display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px}.psFoot289 button{height:46px;border-radius:10px;font-weight:950;font-size:15px}.psClear289{border:1px solid #d1d5db;background:#fff;color:#4b5563}.psAll289{border:1px solid #2563eb;background:#eff6ff;color:#1d4ed8}.psOk289{border:0;background:#087b34;color:#fff}@media(max-width:520px){.psOverlay289{padding:10px}.psSheet289{width:96vw;max-height:88vh}.psGrid289{grid-template-columns:1fr}.psHead289{font-size:16px}}';document.head.appendChild(st)}
function syncBtn(){const b=$('#psTickBtn289'),list=selected();if(b)b.textContent=list.length?`PS: ${list.length===1?list[0]:list.length+' คน'} ▼`:'PS: ทั้งหมด ▼';const c=$('#psCount289');if(c)c.textContent=list.length?`เลือกอยู่ ${list.length} คน: ${list.join(', ')}`:'เลือกอยู่: ทั้งหมด'}
function ensurePsOverlay(){injectPsCss();if(psOverlay)return;psOverlay=document.createElement('div');psOverlay.className='psOverlay289';psOverlay.innerHTML='<div class="psSheet289"><div class="psHead289"><b>เลือก PS แบบติ๊กมาร์ค</b><button class="psClose289">ปิด</button></div><div class="psSearch289"><input id="psSearch289" placeholder="ค้นหา PS"></div><div class="psCount289" id="psCount289">เลือกอยู่: ทั้งหมด</div><div class="psBody289"></div><div class="psFoot289"><button class="psClear289">ล้าง</button><button class="psAll289">เลือกทั้งหมด</button><button class="psOk289">ตกลง</button></div></div>';document.body.appendChild(psOverlay);psBody=psOverlay.querySelector('.psBody289');psOverlay.querySelector('.psClose289').onclick=()=>psOverlay.classList.remove('on');psOverlay.onclick=e=>{if(e.target===psOverlay)psOverlay.classList.remove('on')};psOverlay.querySelector('#psSearch289').oninput=renderPs}
function renderPs(){ensurePsOverlay();const picked=new Set(selected());const q=T($('#psSearch289')?.value).toLowerCase();let list=collectFullPs();if(q)list=list.filter(x=>x.toLowerCase().includes(q));list.sort((a,b)=>(picked.has(b)-picked.has(a))||a.localeCompare(b,'th'));psBody.innerHTML='<div class="psGrid289">'+list.map(x=>`<button class="psItem289 ${picked.has(x)?'on':''}" data-v="${x}"><i>${picked.has(x)?'✓':''}</i><span>${x}</span></button>`).join('')+'</div>';syncBtn()}
function openPs(){ensurePsOverlay();collectFullPs();const s=$('#psSearch289');if(s)s.value='';renderPs();psOverlay.classList.add('on');setTimeout(()=>document.dispatchEvent(new CustomEvent('doit:psPopupOpened')),0)}
function installPsTickButton(){const el=$('#psSelect');if(!el)return;const field=el.closest('.field');if(!field)return;if(!$('#psTickBtn289')){const b=document.createElement('button');b.type='button';b.id='psTickBtn289';b.className='psTickBtn289';b.onclick=openPs;field.insertBefore(b,el)}hideLegacyPsSelect();syncBtn()}
function boot(){cleanSelect();forceCenteredDate();installPsTickButton();collectFullPs();syncBtn();let n=0;const tick=()=>{cleanSelect();forceCenteredDate();installPsTickButton();collectFullPs();if(!document.querySelector('.psOverlay289.on'))syncBtn();if(++n<12)setTimeout(tick,600)};setTimeout(tick,300)}
document.addEventListener('doit:psChanged',()=>{syncBtn();if(document.querySelector('.psOverlay289.on'))renderPs()});document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();